generated_oml:
// C3: Physical sensing components
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Motor current sensor feeding input current I_M from the Robot's controller."
    DTDFVocab:producedData MotorCurrentTopic
]

instance MotorEncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Motor encoder capturing the synchronous motor angle Q."
    DTDFVocab:producedData MotorAngleTopic
]

instance GearboxEncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Gearbox encoder capturing the cycloidal gearbox angle."
    DTDFVocab:producedData GearboxAngleTopic
]

// C4: Physical-to-virtual interaction
instance MotorCurrentTopic : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

instance MotorAngleTopic : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoderSensor
]

instance GearboxAngleTopic : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxEncoderSensor
]

// C10: Models/Data
instance CurrentMeasured : DTDFVocab:Data [
    base:desc "Measured current values streamed over MQTT topic I_M."
    DTDFVocab:inputTo MQTTAdapter
    DTDFVocab:fromData MotorCurrentTopic
]

instance MotorAngleMeasured : DTDFVocab:Data [
    base:desc "Measured motor angle values streamed over MQTT topic Q."
    DTDFVocab:inputTo MQTTAdapter
    DTDFVocab:fromData MotorAngleTopic
]

instance MotorTorqueMeasured : DTDFVocab:Data [
    base:desc "Measured motor torque derived from current I_M and angle Q."
    DTDFVocab:inputTo SimulinkEngine
    DTDFVocab:fromData MotorCurrentTopic, MotorAngleTopic
]

instance MotorAngularVelocityMeasured : DTDFVocab:Data [
    base:desc "Measured motor angular velocity derived from motor angle."
    DTDFVocab:inputTo SimulinkEngine
    DTDFVocab:fromData MotorAngleTopic
]

// C11: Enablers
instance MQTTAdapter : DTDFVocab:Enabler [
    base:desc "Adapts MQTT topics to internal data flow for the DT."
    DTDFVocab:enables FrictionIdentificationService, MotionComparisonService
]

instance SimulinkEngine : DTDFVocab:Enabler [
    base:desc "MATLAB/Simulink engine executing the mechanical dynamics and friction models."
    DTDFVocab:enables SimulationService
]

// C6: Services
instance FrictionIdentificationService : DTDFVocab:Service [
    base:desc "Continuous, multi-physics-aware identification of joint friction using analytical and data-driven models."
    DTDFVocab:provides FrictionParameterInsight, FrictionTrendInsight, UpdateRobotControllerParameters, AlertOperatorAction
]

instance MotionComparisonService : DTDFVocab:Service [
    base:desc "Compares simulated and measured torque/velocity to detect friction losses."
    DTDFVocab:provides TorqueComparisonInsight, MotionAccuracyInsight, AlertOperatorAction
]

instance DiagnosticService : DTDFVocab:Service [
    base:desc "Delivers diagnostics for operators, enabling maintenance decisions."
    DTDFVocab:provides MaintenanceDecisionInsight, LogMaintenanceDecision
]

instance VisualizationService : DTDFVocab:Service [
    base:desc "Live visualization of joint motion data in a unified dashboard."
    DTDFVocab:provides MotionAccuracyInsight, TorqueComparisonInsight
]

instance SimulationService : DTDFVocab:Service [
    base:desc "Runs the Simulink simulation of motor and gearbox dynamics."
    DTDFVocab:provides SimulationModelInsight
]

// C17: Insights/Actions
instance FrictionParameterInsight : DTDFVocab:Insight [
    base:desc "Insight into current friction parameter values for the axis."
]

instance FrictionTrendInsight : DTDFVocab:Insight [
    base:desc "Insight into the trend of friction parameters over time."
]

instance MotionAccuracyInsight : DTDFVocab:Insight [
    base:desc "Insight into the accuracy of joint motion compared to reference."
]

instance MaintenanceDecisionInsight : DTDFVocab:Insight [
    base:desc "Insight used to decide on maintenance interventions."
]

instance TorqueComparisonInsight : DTDFVocab:Insight [
    base:desc "Insight comparing simulated and measured torque to quantify friction losses."
]

instance SimulationModelInsight : DTDFVocab:Insight [
    base:desc "Insight from Simulink simulation of joint torque and velocity."
]

instance UpdateRobotControllerParameters : DTDFVocab:Action [
    base:desc "Updates the robot controller with the newly identified friction parameters."
    DTDFVocab:IsAutomatic true
]

instance LogMaintenanceDecision : DTDFVocab:Action [
    base:desc "Logs maintenance decisions for traceability."
    DTDFVocab:IsAutomatic true
]

instance AlertOperatorAction : DTDFVocab:Action [
    base:desc "Sends alerts to operators when friction trends exceed thresholds."
    DTDFVocab:IsAutomatic true
]

// Components and Environment
instance Axis1Component : DTDFVocab:Component [
    base:desc "First axis of the MABI MAX 0100 industrial robot."
]

instance MotorComponent : DTDFVocab:Component [
    base:desc "Permanent-magnet synchronous motor of Axis1."
]

instance GearboxComponent : DTDFVocab:Component [
    base:desc "Cycloidal gearbox with dual position encoders."
]

instance AxisEnvironment : DTDFVocab:Environment [
    base:contains Axis1Component, MotorComponent, GearboxComponent
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Real‑time continuous data acquisition and model simulation at the control loop rate of the robot (up to 75 [°]/s angular speed, sensors sampled at the controller’s update frequency)."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "A centralized digital twin consisting of: (1) AAS‑based asset descriptor for the MABI MAX axis; (2) Engineering and simulation models (SysML + Simulink) forming the computational core; (3) Data traces and processing pipeline that consumes sensor streams, runs friction models, and aggregates results; (4) Dashboard interface presenting live plots and diagnostics. The constellation orchestrates data flow from PT to DT via MQTT, processing in the PT‑to‑DT pipeline, and visualization to end users."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "Operational phase: the digital shadow is built and maintained during the robot’s in‑service operation for continuous identification and tuning of friction models; it does not cover the design or manufacturing stage of the PT."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Models combine white‑box analytical friction terms (Coulomb‑Viscous, Stribeck, Dahl, LuGre) with data‑driven black‑box components; runtime validation is achieved by comparing simulation outputs with measured data traces; traceability links each data point to its origin (sensor or model) and processing step; uncertainty is reduced through continuous online parameter adaptation and multi‑physics awareness."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Live data from the robot’s controller is published over MQTT (TCP/IP) to the digital shadow; the Asset Administration Shell provides semantic metadata, and the processing components consume these MQTT messages for real‑time analysis."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "Use of SysML (Unified Modeling Language) and Asset Administration Shells (a key Industrie 4.0 standard); adherence to UML class diagrams for the reference model."
]
